};

export default Home;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Sparkles, User, Bot, ArrowRight } from 'lucide-react';
import { useApp } from '../store';
import { GoogleGenAI } from "@google/genai";

const ChatWidget = () => {
  const { siteSettings } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [activeMode, setActiveMode] = useState<'menu' | 'ai'>('menu');
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const whatsappLink = siteSettings.socials?.whatsapp || `https://wa.me/${siteSettings.whatsappNumber.replace(/[^0-9]/g, '')}`;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, activeMode]);

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: [
                { role: 'user', parts: [{ text: userMsg }] }
            ],
            config: {
                tools: [{ googleSearch: {} }],
                systemInstruction: `You are a helpful AI assistant for DigiStore AZ, a premium digital marketplace. Guide users on buying software keys, accounts, and AI tools. Currency: AZN.`
            }
        });

        const aiResponse = response.text || "Bağışlayın, cavab verə bilmirəm.";
        setMessages(prev => [...prev, { role: 'model', text: aiResponse }]);
    } catch (error) {
        setMessages(prev => [...prev, { role: 'model', text: "Xəta baş verdi. Zəhmət olmasa WhatsApp-a yazın." }]);
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">

      {isOpen && (
        <div className="mb-4 w-80 md:w-96 glass rounded-3xl shadow-2xl overflow-hidden animate-slide-up flex flex-col max-h-[550px] border border-white/10">

            {/* Header */}
            <div className="bg-gradient-to-r from-primary to-accent p-5 flex justify-between items-center text-white">
                <div>
                    <h3 className="font-bold text-lg">{activeMode === 'ai' ? 'DigiStore AI' : 'Kömək lazımdır?'}</h3>
                    <p className="text-white/80 text-xs">{activeMode === 'ai' ? 'Süni İntellekt Dəstəyi' : 'Bizə yazın'}</p>
                </div>
                <div className="flex gap-2">
                    {activeMode === 'ai' && (
                        <button onClick={() => setActiveMode('menu')} className="bg-white/20 p-2 rounded-full hover:bg-white/30 transition-colors">
                           <ArrowRight className="w-4 h-4 rotate-180" />
                        </button>
                    )}
                    <button onClick={() => setIsOpen(false)} className="bg-white/20 p-2 rounded-full hover:bg-white/30 transition-colors">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            </div>

            {/* Menu Mode */}
            {activeMode === 'menu' && (
                <div className="p-6 bg-surface/90 backdrop-blur-xl">
                    <button 
                        onClick={() => window.open(whatsappLink, '_blank')}
                        className="w-full bg-[#25D366] text-white p-4 rounded-2xl flex items-center gap-4 mb-4 hover:shadow-lg hover:shadow-green-500/20 transition-all group"
                    >
                        <div className="bg-white/20 p-2 rounded-full"><MessageCircle className="w-6 h-6" /></div>
                        <div className="text-left">
                            <p className="font-bold">WhatsApp</p>
                            <p className="text-xs opacity-90">Canlı Operatorla əlaqə</p>
                        </div>
                        <ArrowRight className="ml-auto w-5 h-5 opacity-50 group-hover:translate-x-1 transition-transform" />
                    </button>

                    <button 
                        onClick={() => setActiveMode('ai')}
                        className="w-full bg-surfaceHighlight border border-white/5 text-white p-4 rounded-2xl flex items-center gap-4 hover:bg-white/5 transition-all group"
                    >
                        <div className="bg-gradient-to-br from-primary to-accent p-2 rounded-full"><Sparkles className="w-6 h-6 text-white" /></div>
                        <div className="text-left">
                            <p className="font-bold">AI Asistan</p>
                            <p className="text-xs text-gray-400">Anında sual-cavab</p>
                        </div>
                        <ArrowRight className="ml-auto w-5 h-5 opacity-50 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            )}

            {/* AI Chat Mode */}
            {activeMode === 'ai' && (
                <div className="flex flex-col h-[400px] bg-surface/90 backdrop-blur-xl">
                    <div className="flex-1 overflow-y-auto p-4 space-y-4">
                        {messages.length === 0 && (
                            <div className="text-center text-gray-500 text-sm mt-8 px-4">
                                <Bot className="w-12 h-12 mx-auto mb-3 text-primary opacity-50"/>
                                <p>Salam! Mən DigiStore AI asistanıyam. Sizə məhsullar və xidmətlər barədə necə kömək edə bilərəm?</p>
                            </div>
                        )}
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] p-3 text-sm rounded-2xl ${
                                    msg.role === 'user' 
                                    ? 'bg-primary text-white rounded-tr-sm' 
                                    : 'bg-surfaceHighlight text-gray-200 rounded-tl-sm border border-white/5'
                                }`}>
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {isLoading && <div className="text-xs text-gray-500 p-2 animate-pulse">Yazır...</div>}
                        <div ref={messagesEndRef} />
                    </div>

                    <form onSubmit={handleAiSubmit} className="p-3 border-t border-white/5 bg-black/20 flex gap-2">
                        <input 
                            className="flex-1 bg-surfaceHighlight border border-white/5 rounded-full px-4 py-2 text-sm text-white focus:outline-none focus:border-primary placeholder-gray-500"
                            placeholder="Sualınızı yazın..."
                            value={input}
                            onChange={e => setInput(e.target.value)}
                        />
                        <button type="submit" disabled={isLoading} className="bg-primary text-white p-2 rounded-full hover:bg-primary-dark transition-colors disabled:opacity-50">
                            <Send className="w-4 h-4" />
                        </button>
                    </form>
                </div>
            )}
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="bg-gradient-to-r from-primary to-accent text-white p-4 rounded-full shadow-[0_0_20px_rgba(99,102,241,0.4)] transition-all hover:scale-110"
      >
        {isOpen ? <X className="w-6 h-6" /> : <MessageCircle className="w-6 h-6" />}
      </button>
    </div>
  );
};

export default ChatWidget;

import React, { useState, useEffect } from 'react';
import { ShoppingCart, X, Trash2, Plus, Minus, ArrowRight } from 'lucide-react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';

const CartWidget = () => {
  const { cart, updateCartQuantity, removeFromCart } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [bump, setBump] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (cart.length === 0) return;
    setBump(true);
    const timer = setTimeout(() => setBump(false), 300);
    return () => clearTimeout(timer);
  }, [cart.length]);

  const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <>
      {isOpen && (
        <div className="fixed inset-0 bg-black/80 z-[60] backdrop-blur-sm transition-opacity" onClick={() => setIsOpen(false)} />
      )}

      <div className={`fixed top-0 right-0 h-full w-full sm:w-[420px] bg-surface/95 border-l border-white/10 z-[70] transform transition-transform duration-300 ease-out shadow-2xl flex flex-col backdrop-blur-xl ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>

         {/* Header */}
         <div className="p-6 border-b border-white/5 flex justify-between items-center bg-black/20">
            <h2 className="text-xl font-bold text-white flex items-center gap-3">
                Səbətiniz
                <span className="bg-primary/20 text-primary text-xs px-2 py-1 rounded-full">{cart.length}</span>
            </h2>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white p-2 hover:bg-white/5 rounded-full"><X /></button>
         </div>

         {/* Items */}
         <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-4">
                    <div className="w-24 h-24 bg-surfaceHighlight rounded-full flex items-center justify-center mb-2">
                        <ShoppingCart className="w-10 h-10 opacity-30" />
                    </div>
                    <p className="font-medium text-lg">Səbətiniz boşdur</p>
                    <button onClick={() => setIsOpen(false)} className="text-primary hover:text-white transition-colors">Alış-verişə davam et</button>
                </div>
            ) : (
                cart.map((item, index) => (
                    <div key={index} className="flex gap-4 p-4 rounded-2xl bg-surfaceHighlight/50 border border-white/5 hover:border-primary/30 transition-colors group">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-black/50 shrink-0">
                            <img src={item.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt={item.title} />
                        </div>
                        <div className="flex-1 flex flex-col justify-between">
                            <div>
                                <h4 className="font-bold text-white text-sm line-clamp-1">{item.title}</h4>
                                {item.userInput && <p className="text-xs text-gray-400 mt-1">{item.userInput}</p>}
                            </div>

                            <div className="flex items-center justify-between mt-3">
                                <div className="text-white font-bold">{item.price.toFixed(2)} <span className="text-primary text-xs">₼</span></div>

                                <div className="flex items-center gap-3">
                                    <div className="flex items-center bg-black/30 rounded-lg p-0.5">
                                        <button onClick={() => updateCartQuantity(index, -1)} className="p-1.5 text-gray-400 hover:text-white"><Minus className="w-3 h-3"/></button>
                                        <span className="text-xs font-bold w-6 text-center text-white">{item.quantity}</span>
                                        <button onClick={() => updateCartQuantity(index, 1)} className="p-1.5 text-gray-400 hover:text-white"><Plus className="w-3 h-3"/></button>
                                    </div>
                                    <button onClick={() => removeFromCart(index)} className="text-gray-500 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4"/></button>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            )}
         </div>

         {/* Footer */}
         <div className="p-6 border-t border-white/5 bg-black/20">
            <div className="flex justify-between mb-6">
                <span className="text-gray-400">Cəmi Məbləğ</span>
                <span className="text-2xl font-bold text-white">{subTotal.toFixed(2)} <span className="text-primary">₼</span></span>
            </div>
            <button 
                onClick={() => { setIsOpen(false); navigate('/cart'); }}
                className="w-full bg-white text-black font-bold py-4 rounded-xl hover:bg-gray-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                disabled={cart.length === 0}
            >
                Sifarişi Rəsmiləşdir <ArrowRight className="w-5 h-5" />
            </button>
         </div>
      </div>

      {/* Floating Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 left-6 z-[50] glass text-white p-4 rounded-full shadow-lg transition-all duration-300 transform hover:scale-110 flex items-center justify-center group ${bump ? 'scale-110 ring-2 ring-primary' : ''}`}
      >
        <ShoppingCart className="w-6 h-6 text-primary group-hover:text-white transition-colors" />
        {cart.length > 0 && (
            <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full border-2 border-background shadow-sm">
                {cart.length}
            </span>
        )}
      </button>
    </>
  );
};

export default CartWidget;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import { Product } from '../types';
import { ArrowLeft, CheckCircle, ShieldCheck, ShoppingCart, Heart, Star, MessageSquare, Send, Zap } from 'lucide-react';

const ProductView = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { products, addToCart, user, toggleWishlist, isAuthenticated, comments, addComment } = useApp();

  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [userInput, setUserInput] = useState('');
  const [added, setAdded] = useState(false);
  const [activeTab, setActiveTab] = useState<'desc' | 'reviews'>('desc');
  const [reviewText, setReviewText] = useState('');
  const [reviewRating, setReviewRating] = useState(5);

  useEffect(() => {
    const found = products.find(p => p.id === id);
    if (found) setProduct(found);
    else navigate('/');
  }, [id, products, navigate]);

  if (!product) return null;

  const isLiked = user?.wishlist?.includes(product.id);
  const finalPrice = product.price - (product.price * (product.discountPercent / 100));

  const productComments = comments.filter(c => c.targetId === product.id && c.isApproved && c.type === 'product');
  const avgRating = productComments.length > 0 
      ? productComments.reduce((acc, c) => acc + (c.rating || 0), 0) / productComments.length 
      : 0;

  const handleAddToCart = () => {
    if (product.requiresInput && !userInput) {
      alert("Zəhmət olmasa tələb olunan məlumatı daxil edin.");
      return;
    }
    addToCart(product, userInput);
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  const handleWishlist = () => {
      if(!isAuthenticated) {
          navigate('/auth');
          return;
      }
      toggleWishlist(product.id);
  };

  const submitReview = (e: React.FormEvent) => {
      e.preventDefault();
      if(!isAuthenticated) {
          alert("Rəy yazmaq üçün daxil olun.");
          navigate('/auth');
          return;
      }
      if(!reviewText.trim()) return;

      addComment({
          author: user?.name || 'Anonim',
          content: reviewText,
          type: 'product',
          targetId: product.id,
          rating: reviewRating
      });

      setReviewText('');
      setReviewRating(5);
      alert("Rəyiniz əlavə olundu!");
  };

  return (
    <div className="min-h-screen pt-24 pb-10 px-4">
      <div className="max-w-6xl mx-auto">
        <button onClick={() => navigate('/')} className="flex items-center text-gray-400 hover:text-white mb-8 group transition-colors">
            <div className="bg-white/5 p-2 rounded-full mr-2 group-hover:bg-white/10">
                <ArrowLeft className="w-4 h-4" />
            </div>
            Mağazaya Qayıt
        </button>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 mb-12">

            {/* Image Side */}
            <div className="relative">
                <div className="aspect-square rounded-3xl overflow-hidden glass border border-white/10 relative z-10">
                    <img src={product.image} alt={product.title} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-background via-transparent to-transparent opacity-60"></div>
                </div>
                {/* Back glow */}
                <div className="absolute top-10 -left-10 w-full h-full bg-primary/20 blur-[100px] rounded-full z-0"></div>
            </div>

            {/* Info Side */}
            <div className="flex flex-col justify-center">
                <div className="flex justify-between items-start mb-4">
                    <h1 className="text-4xl font-bold text-white leading-tight">{product.title}</h1>
                    <button 
                        onClick={handleWishlist}
                        className={`p-3 rounded-full border transition-all ${isLiked ? 'bg-red-500 text-white border-red-500' : 'glass border-white/10 text-gray-400 hover:text-white'}`}
                    >
                        <Heart className={`w-6 h-6 ${isLiked ? 'fill-current' : ''}`} />
                    </button>
                </div>

                <div className="flex items-center gap-4 mb-8">
                    <div className="flex text-amber-400">
                        {[1,2,3,4,5].map(star => (
                            <Star key={star} className={`w-4 h-4 ${star <= Math.round(avgRating) ? 'fill-current' : 'text-gray-700'}`} />
                        ))}
                    </div>
                    <span className="text-sm text-gray-400">({productComments.length} rəy)</span>
                    <span className="w-1 h-1 bg-gray-600 rounded-full"></span>
                    <span className="text-sm text-primary font-medium flex items-center gap-1"><ShieldCheck className="w-4 h-4"/> Rəsmi Zəmanət</span>
                </div>

                <div className="flex items-end gap-4 mb-8 p-6 glass rounded-2xl border-l-4 border-primary">
                    <div className="flex flex-col">
                         <span className="text-sm text-gray-400 mb-1">Qiymət</span>
                         <div className="text-4xl font-bold text-white">{finalPrice.toFixed(2)} <span className="text-primary text-xl">₼</span></div>
                    </div>
                    {product.discountPercent > 0 && (
                        <div className="mb-2">
                             <span className="text-lg text-gray-500 line-through mr-2">{product.price.toFixed(2)} ₼</span>
                             <span className="bg-red-500/20 text-red-400 text-xs px-2 py-1 rounded font-bold">-{product.discountPercent}%</span>
                        </div>
                    )}
                </div>

                {product.requiresInput && (
                  <div className="mb-8">
                    <label className="block text-sm font-bold text-gray-300 mb-2 pl-1">
                      {product.inputLabel || "Account ID / Link"} <span className="text-primary">*</span>
                    </label>
                    <input
                      type="text"
                      value={userInput}
                      onChange={(e) => setUserInput(e.target.value)}
                      className="w-full bg-surfaceHighlight border border-white/10 rounded-xl p-4 text-white focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                      placeholder="Məlumatı daxil edin..."
                    />
                  </div>
                )}

                <div className="flex gap-4">
                    <button
                        onClick={handleAddToCart}
                        className={`flex-1 font-bold py-4 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg hover:translate-y-[-2px]
                            ${added ? 'bg-green-600 text-white' : 'bg-white text-black hover:bg-gray-200'}`}
                    >
                        {added ? (
                            <>
                                <CheckCircle className="w-5 h-5" /> Əlavə olundu
                            </>
                        ) : (
                            <>
                                <ShoppingCart className="w-5 h-5" /> Səbətə At
                            </>
                        )}
                    </button>

                    <button className="p-4 glass rounded-xl text-gray-400 hover:text-white hover:bg-white/10 transition-colors">
                        <MessageSquare className="w-6 h-6" />
                    </button>
                </div>
            </div>
        </div>

        {/* Tabs & Content */}
        <div className="glass rounded-3xl p-1 overflow-hidden">
            <div className="flex border-b border-white/5 bg-black/20">
                 <button 
                    onClick={() => setActiveTab('desc')}
                    className={`flex-1 py-4 font-bold text-sm uppercase tracking-wider transition-colors 
                        ${activeTab === 'desc' ? 'text-white border-b-2 border-primary bg-white/5' : 'text-gray-500 hover:text-gray-300'}`}
                 >
                     Məhsul Haqqında
                 </button>
                 <button 
                    onClick={() => setActiveTab('reviews')}
                    className={`flex-1 py-4 font-bold text-sm uppercase tracking-wider transition-colors 
                        ${activeTab === 'reviews' ? 'text-white border-b-2 border-primary bg-white/5' : 'text-gray-500 hover:text-gray-300'}`}
                 >
                     Rəylər ({productComments.length})
                 </button>
            </div>

            <div className="p-8 md:p-12">
                 {activeTab === 'desc' && (
                     <div className="animate-fade-in text-gray-300 leading-relaxed whitespace-pre-wrap text-lg">
                         {product.description}
                     </div>
                 )}

                 {activeTab === 'reviews' && (
                     <div className="animate-fade-in space-y-8">
                         {productComments.length === 0 ? (
                             <div className="text-center py-10 bg-white/5 rounded-2xl">
                                 <p className="text-gray-500">Bu məhsul üçün hələ rəy yoxdur.</p>
                             </div>
                         ) : (
                             productComments.map((comment) => (
                                 <div key={comment.id} className="bg-white/5 p-6 rounded-2xl border border-white/5">
                                     <div className="flex justify-between items-start mb-3">
                                         <div className="flex items-center gap-3">
                                             <div className="w-10 h-10 rounded-full bg-gradient-to-r from-primary to-accent flex items-center justify-center font-bold text-white shadow-lg">
                                                 {comment.author.charAt(0)}
                                             </div>
                                             <div>
                                                 <p className="font-bold text-white">{comment.author}</p>
                                                 <div className="flex text-amber-400 text-xs mt-0.5">
                                                    {[1,2,3,4,5].map(s => (
                                                        <Star key={s} className={`w-3 h-3 ${s <= (comment.rating || 5) ? 'fill-current' : 'text-gray-700'}`} />
                                                    ))}
                                                 </div>
                                             </div>
                                         </div>
                                         <span className="text-xs text-gray-600">{new Date(comment.date).toLocaleDateString()}</span>
                                     </div>
                                     <p className="text-gray-300 pl-13 ml-13">{comment.content}</p>
                                 </div>
                             ))
                         )}

                         {isAuthenticated && (
                             <form onSubmit={submitReview} className="mt-8 pt-8 border-t border-white/5">
                                 <h3 className="font-bold text-white mb-4">Rəy Yazın</h3>
                                 <textarea
                                     className="w-full bg-surfaceHighlight border border-white/10 rounded-xl p-4 text-white focus:border-primary outline-none h-32 resize-none mb-4"
                                     placeholder="Fikirləriniz..."
                                     value={reviewText}
                                     onChange={(e) => setReviewText(e.target.value)}
                                 ></textarea>
                                 <button type="submit" className="bg-primary hover:bg-primary-dark text-white font-bold py-2 px-8 rounded-xl transition-colors">
                                     Göndər
                                 </button>
                             </form>
                         )}
                     </div>
                 )}
            </div>
        </div>

      </div>
    </div>
  );
};

export default ProductView;

