          {/* Mobile Menu Button */}
          <div className="flex md:hidden items-center gap-4">
             {isAuthenticated && (
                <Link to="/profile" className="h-8 w-8 rounded-full bg-gradient-to-r from-primary to-secondary flex items-center justify-center text-white text-xs font-bold">
                    {user?.name.charAt(0)}
